  { source_name: 'Google News PT - Ciberseguranca', feed_url: 'https://news.google.com/rss/search?q=ciberseguranca+portugal&hl=pt-PT&gl=PT&ceid=PT:pt-150', topic: 'ciberseguranca' },
  { source_name: 'Google News PT - Automacao', feed_url: 'https://news.google.com/rss/search?q=automacao+empresarial+portugal&hl=pt-PT&gl=PT&ceid=PT:pt-150', topic: 'automacao' }
];

return feeds.map((feed) => ({ json: feed }));

// Pure JS hash (no require needed) — FNV-1a 128-bit hex
function fnv1aHash(str) {
  let h1 = 0x811c9dc5 >>> 0;
  let h2 = 0x811c9dc5 >>> 0;
  for (let i = 0; i < str.length; i++) {
    const c = str.charCodeAt(i);
    h1 = Math.imul(h1 ^ c, 0x01000193) >>> 0;
    h2 = Math.imul(h2 ^ (c + i), 0x01000193) >>> 0;
  }
  return h1.toString(16).padStart(8, '0') + h2.toString(16).padStart(8, '0') +
    (h1 ^ h2).toString(16).padStart(8, '0') + (h1 + h2).toString(16).padStart(8, '0');
}

function normalizeUrl(value) {
  try {
    const u = new URL(value || '');
    u.hash = '';
    u.searchParams.delete('utm_source');
    u.searchParams.delete('utm_medium');
    u.searchParams.delete('utm_campaign');
    return u.toString();
  } catch {
    return value || '';
  }
}

function toIsoDate(value) {
  if (!value) return null;
  const d = new Date(value);
  return Number.isNaN(d.getTime()) ? null : d.toISOString();
}

return items.map((item) => {
  const sourceName = item.json.source_name || item.json.source || 'unknown';
  const title = String(item.json.title || '').trim();
  const summary = String(item.json.contentSnippet || item.json.content || '').trim();
  const rawLink = item.json.link || item.json.id || '';
  const canonicalUrl = normalizeUrl(rawLink);
  const topic = item.json.topic || 'geral';
  const publishedAt = toIsoDate(item.json.isoDate || item.json.pubDate);
  const fingerprint = fnv1aHash((title + '|' + canonicalUrl).toLowerCase());

  return {
    json: {
      source_name: sourceName,
      source_url: rawLink || canonicalUrl,
      canonical_url: canonicalUrl || rawLink,
      title,
      summary,
      content: summary,
      language: 'pt',
      topic,
      published_at: publishedAt,
      trust_score: 50,
      duplicate_fingerprint: fingerprint,
      metadata: {
        pipeline: 'WF-01',
        collected_via: 'rss',
        feed_url: item.json.feedUrl || item.json.feed_url || null
      }
    }
  };
});
